import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"Latent Space — 2026-05-08","description":"","frontmatter":{"title":"Latent Space — 2026-05-08","date":"2026-05-08T00:00:00.000Z","source":"Latent Space","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-08-latent-space.md","filePath":"research/ai-news/2026-05/2026-05-08-latent-space.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-08-latent-space.md"};function i(o,e,l,p,c,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🔬-latent-space-—-2026-05-08" tabindex="-1">🔬 Latent Space — 2026-05-08 <a class="header-anchor" href="#🔬-latent-space-—-2026-05-08" aria-label="Permalink to &quot;🔬 Latent Space — 2026-05-08&quot;">​</a></h1><blockquote><p>swyx 開發者簡報，未公開專案 + 工程視角 來源：<a href="https://www.latent.space/feed" target="_blank" rel="noreferrer">Latent Space</a></p></blockquote><hr><h2 id="ainews-gpt-realtime-2-translate-and-whisper-new-sota-realtime-voice-apis" tabindex="-1"><a href="https://www.latent.space/p/ainews-gpt-realtime-2-translate-and" target="_blank" rel="noreferrer">[AINews] GPT-Realtime-2, -Translate, and -Whisper: new SOTA realtime voice APIs</a> <a class="header-anchor" href="#ainews-gpt-realtime-2-translate-and-whisper-new-sota-realtime-voice-apis" aria-label="Permalink to &quot;[[AINews] GPT-Realtime-2, -Translate, and -Whisper: new SOTA realtime voice APIs](https://www.latent.space/p/ainews-gpt-realtime-2-translate-and)&quot;">​</a></h2><p><em>🔬 Latent Space | 2026-05-08</em></p><p>OpenAI launched <a href="https://x.com/OpenAIDevs/status/2026014334787461508" target="_blank" rel="noreferrer">realtime-1.5</a> 3 months ago, but it was a relative drop in the bucket because it was still 4o based intelligence (a +5% bump in Big Bench Audio). You could tell the sheer confidence in today’s realtime-2 release (with a +15.2% bump in BBA), and it was <a href="https://x.com/OpenAI/status/2052438194625593804?s=20" target="_blank" rel="noreferrer">appropriately well received</a>:</p><p>As<a href="https://openai.com/index/advancing-voice-intelligence-with-new-models-in-the-api/" target="_blank" rel="noreferrer"> the blogpost</a> explains, 3 models are being released, which one might simplify to “voice-in, voice-out, and voice-to-voice”:</p><p>The focus is less about “voice quality”, and more on usability. TLDR:</p><p>Preambles: Developers can enable short phrases before a main response, like “let me check that” or “one moment while I look into it”.</p><p>Parallel tool calls and tool transparency: The model can call multiple tools at once and make those actions audible with phrases like “checking your calendar” or “looking that up now,” helping agents stay responsive while completing tasks.</p><p>Stronger recovery behavior: The model can recover more gracefully by saying things like “I’m having trouble with that right now,” instead of failing or breaking.</p><p>Longer context: 32K → 128K</p><p>Stronger domain understanding: The model better retains specialized terminology, proper nouns, healthcare terms, and other vocabulary</p><p>More controllable tone and delivery: The model can better adjust its tone—speaking calmly, empathetically, or upbeat, based on context</p><p>Adjustable reasoning effort: Developers can now select from minimal, low, medium, high, and xhigh reasoning levels, with low as the default.</p><p>The Demo video showed off how the audio model is better tuned when the main speaker is speaking to someone else, so it stops interrupting so much:</p><p>AI News for 5/6/2026-5/7/2026. We checked 12 subreddits, <a href="https://twitter.com/i/lists/1585430245762441216" target="_blank" rel="noreferrer">544 Twitters</a> and no further Discords. <a href="https://news.smol.ai/" target="_blank" rel="noreferrer">AINews’ website</a> lets you search all past issues. As a reminder, <a href="https://www.latent.space/p/2026" target="_blank" rel="noreferrer">AINews is now a section of Latent Space</a>. You can <a href="https://support.substack.com/hc/en-us/articles/8914938285204-How-do-I-subscribe-to-or-unsubscribe-from-a-section-on-Substack" target="_blank" rel="noreferrer">opt in/out</a> of email frequencies!</p><p>AI Twitter Recap</p><p>Top Story: GPT-Realtime-2 and OpenAI voice AI commentary</p><p>What happened</p><p>OpenAI launched three new streaming audio models in the Realtime API: GPT-Realtime-2, GPT-Realtime-Translate, and GPT-Realtime-Whisper. OpenAI positioned GPT-Realtime-2 as its “most intelligent voice model yet,” bringing “GPT-5-class reasoning” to real-time voice agents that can listen, reason, handle interruptions, use tools, and sustain longer conversations as they unfold <a href="https://x.com/OpenAI/status/2052438194625593804" target="_blank" rel="noreferrer">@OpenAI</a>. The companion models target live speech translation and transcription: GPT-Realtime-Translate supports streaming translation from 70+ input languages into 13 output languages, while GPT-Realtime-Whisper streams transcription/captions as speech is produced <a href="https://x.com/OpenAI/status/2052438196454379986" target="_blank" rel="noreferrer">@OpenAI</a>, <a href="https://x.com/OpenAIDevs/status/2052440907933474954" target="_blank" rel="noreferrer">@OpenAIDevs</a>. OpenAI said the models are available in the Realtime API now, while ChatGPT voice upgrades are still pending: “Stay tuned, we’re cooking” <a href="https://x.com/OpenAI/status/2052438197695877316" target="_blank" rel="noreferrer">@OpenAI</a>. Sam Altman framed the launch around a behavioral shift: users increasingly use voice with AI when they need to “dump” lots of context, and OpenAI is also working on improvements to ChatGPT voice <a href="https://x.com/sama/status/2052462271667028211" target="_blank" rel="noreferrer">@sama</a>.</p><p>Facts vs. opinions</p><p>Factual / directly claimed by OpenAI and evaluators</p><p>Model family: GPT-Realtime-2, GPT-Realtime-Translate, GPT-Realtime-Whisper are available in the Realtime API today <a href="https://x.com/OpenAIDevs/status/2052440968763515223" target="_blank" rel="noreferrer">@OpenAIDevs</a>.</p><p>GPT-Realtime-2 capabilities: reasoning-oriented native speech-to-speech model for production voice agents; supports tool use/action, interruption recovery, longer conversations, and “GPT-5-class reasoning” per OpenAI’s wording <a href="https://x.com/OpenAI/status/2052438194625593804" target="_blank" rel="noreferrer">@OpenAI</a>, <a href="https://x.com/reach_vb/status/2052438371058737280" target="_blank" rel="noreferrer">@reach_vb</a>.</p><p>Context window: community/OpenAI-dev commentary reported 128K context for GPT-Realtime-2 voice agents <a href="https://x.com/reach_vb/status/2052438371058737280" target="_blank" rel="noreferrer">@reach_vb</a>; Artificial Analysis independently reported the context window increased from 32K to 128K, with 32K max output tokens <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Translation: GPT-Realtime-Translate supports live speech translation from 70+ input languages into 13 output languages <a href="https://x.com/OpenAI/status/2052438196454379986" target="_blank" rel="noreferrer">@OpenAI</a>, <a href="https://x.com/reach_vb/status/2052438371058737280" target="_blank" rel="noreferrer">@reach_vb</a>.</p><p>Transcription: GPT-Realtime-Whisper provides low-latency streaming transcription in the Realtime API for captions, notes, and continuous speech understanding <a href="https://x.com/OpenAIDevs/status/2052440957258489859" target="_blank" rel="noreferrer">@OpenAIDevs</a>.</p><p>Prompting/control: OpenAI published a voice prompting guide covering reasoning effort, preambles, tool behavior, unclear audio handling, exact entity capture, and state maintenance in long sessions <a href="https://x.com/OpenAIDevs/status/2052530378184032560" target="_blank" rel="noreferrer">@OpenAIDevs</a>.</p><p>Independent benchmarks: Scale AI reported GPT-Realtime-2 took the top spot on its Audio MultiChallenge S2S leaderboard, with instruction retention rising from 36.7% to 70.8% APR versus GPT-Realtime-1.5 and strong performance on voice editing/real-time repair <a href="https://x.com/ScaleAILabs/status/2052451341071683732" target="_blank" rel="noreferrer">@ScaleAILabs</a>.</p><p>Independent benchmarks: Artificial Analysis reported 96.6% on Big Bench Audio speech-to-speech reasoning, 96.1% on its Conversational Dynamics benchmark, average time-to-first-audio of 2.33s at high reasoning and 1.12s at minimal reasoning, and unchanged audio pricing of $1.15/hour input and $4.61/hour output <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>, <a href="https://x.com/ArtificialAnlys/status/2052486478501204415" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Reasoning-effort controls: Artificial Analysis reported adjustable reasoning levels: minimal, low, medium, high, xhigh, with low as default <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Enterprise/product evals: Glean said GPT-Realtime-2 delivered a 42.9% relative increase in helpfulness over the previous version in internal evals for real-time organizational voice interactions <a href="https://x.com/glean/status/2052440702169108990" target="_blank" rel="noreferrer">@glean</a>. Genspark said its Call for Me Agent moved to GPT-Realtime-2 and saw +26% effective conversation rate and fewer dropped calls <a href="https://x.com/genspark_ai/status/2052524670088556557" target="_blank" rel="noreferrer">@genspark_ai</a>.</p><p>Opinions / interpretation / commentary</p><p>Supporters described the launch as a “big step forward” for voice agents <a href="https://x.com/sama/status/2052462271667028211" target="_blank" rel="noreferrer">@sama</a>, “total realtime victory” <a href="https://x.com/reach_vb/status/2052442056392405383" target="_blank" rel="noreferrer">@reach_vb</a>, and the first speech-to-speech model good enough for “real work” in complex voice agents <a href="https://x.com/kwindla/status/2052521318688739811" target="_blank" rel="noreferrer">@kwindla</a>.</p><p>A more cautious view: Simon Willison noted the announcement does not mean ChatGPT Voice Mode itself has upgraded yet; the ChatGPT upgrade “sounds” like it is coming soon <a href="https://x.com/simonw/status/2052439091577496054" target="_blank" rel="noreferrer">@simonw</a>, <a href="https://x.com/simonw/status/2052439181885153757" target="_blank" rel="noreferrer">@simonw</a>.</p><p>Interface skepticism: Will Depue compared audio to VR—frequently exciting, but historically not sticky as an interface—while arguing that real-time tool use, reasoning while speaking, and live translation are the kinds of capabilities that could make audio interfaces finally take off <a href="https://x.com/willdepue/status/2052493097586823353" target="_blank" rel="noreferrer">@willdepue</a>.</p><p>Broader UX optimism: several commenters framed voice as more natural and bandwidth-efficient for humans <a href="https://x.com/BorisMPower/status/2052471142921994332" target="_blank" rel="noreferrer">@BorisMPower</a>, a path toward Jarvis-like always-available computer agents <a href="https://x.com/willdepue/status/2052494388413235672" target="_blank" rel="noreferrer">@willdepue</a>, or eventually displaced by even higher-bandwidth BCIs <a href="https://x.com/iScienceLuvr/status/2052465922640593068" target="_blank" rel="noreferrer">@iScienceLuvr</a>.</p><p>Competitive context: Elon Musk pushed Grok Voice for customer support <a href="https://x.com/elonmusk/status/2052530063913189879" target="_blank" rel="noreferrer">@elonmusk</a>, underscoring that real-time voice support/customer-service automation is now a competitive surface across labs.</p><p>Technical details and benchmark data</p><p>GPT-Realtime-2</p><p>Native speech-to-speech / real-time voice model, released via OpenAI’s Realtime API <a href="https://x.com/OpenAI/status/2052438194625593804" target="_blank" rel="noreferrer">@OpenAI</a>.</p><p>Framed as “GPT-5-class reasoning” for voice agents <a href="https://x.com/OpenAI/status/2052438194625593804" target="_blank" rel="noreferrer">@OpenAI</a>.</p><p>Designed for agents that can:</p><p>reason mid-conversation,</p><p>use tools/take actions,</p><p>handle interruptions,</p><p>recover when users revise or repair speech,</p><p>sustain longer sessions with expanded context <a href="https://x.com/OpenAI/status/2052438196454379986" target="_blank" rel="noreferrer">@OpenAI</a>, <a href="https://x.com/reach_vb/status/2052438371058737280" target="_blank" rel="noreferrer">@reach_vb</a>.</p><p>Reported context: 128K tokens, up from 32K <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Reported max output: 32K tokens <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Inputs reported by Artificial Analysis: text, audio, and image <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Reasoning effort levels: minimal, low, medium, high, xhigh; default low <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Time-to-first-audio:</p><p>1.12s at minimal reasoning,</p><p>2.33s at high reasoning <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Pricing:</p><p>$1.15/hour audio input,</p><p>$4.61/hour audio output,</p><p>unchanged versus prior model according to Artificial Analysis <a href="https://x.com/ArtificialAnlys/status/2052486478501204415" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Conversational features: supports short preambles before main responses—e.g. “let me check that”—and audible transparency during tool calls—e.g. “checking your calendar” <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Benchmarks</p><p>Scale AI Audio MultiChallenge S2S: GPT-Realtime-2 placed #1; instruction retention improved from 36.7% to 70.8% APR versus GPT-Realtime-1.5; strong voice editing when users repair/revise speech in real time <a href="https://x.com/ScaleAILabs/status/2052451341071683732" target="_blank" rel="noreferrer">@ScaleAILabs</a>.</p><p>Artificial Analysis Big Bench Audio: GPT-Realtime-2 high variant scored 96.6%, reported as equal to Gemini 3.1 Flash Live Preview High and about ~13% above the previous highest result <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>Justin Uberti separately summarized the improvement as 15 percentage points vs. GPT-Realtime-1.5 on Big Bench Audio, near saturation <a href="https://x.com/juberti/status/2052507302092296252" target="_blank" rel="noreferrer">@juberti</a>.</p><p>Conversational Dynamics / Full Duplex Bench subset: GPT-Realtime-2 minimal variant scored 96.1%, with strengths in pause handling and turn-taking <a href="https://x.com/ArtificialAnlys/status/2052486470469140777" target="_blank" rel="noreferrer">@ArtificialAnlys</a>.</p><p>GPT-Realtime-Translate</p><p>Live streaming speech translation from 70+ input languages to 13 output languages <a href="https://x.com/OpenAI/status/2052438196454379986" target="_blank" rel="noreferrer">@OpenAI</a>.</p><p>OpenAI cofounder Greg Brockman said real-time voice-to-voice translation has been an anticipated OpenAI application since the company’s early days and is now available for anyone to build with <a href="https://x.com/gdb/status/2052480998668206262" target="_blank" rel="noreferrer">@gdb</a>.</p><p>Vimeo demonstrated live dubbing with no pre-loaded captions, showing translations generated fully live <a href="https://x.com/Vimeo/status/2052442588201029684" target="_blank" rel="noreferrer">@Vimeo</a>.</p><p>Junling Zhang highlighted the new real-time translation model and encouraged API usage <a href="https://x.com/jxnlco/status/2052449634266812744" target="_blank" rel="noreferrer">@jxnlco</a>.</p><p>Boris Power said live translation “actually works incredibly well” and plans to use it regularly <a href="https://x.com/BorisMPower/status/2052472038967890022" target="_blank" rel="noreferrer">@BorisMPower</a>.</p><p>GPT-Realtime-Whisper</p><p>Streaming transcription as people speak, for real-time captions, notes, and speech understanding <a href="https://x.com/OpenAI/status/2052438196454379986" target="_blank" rel="noreferrer">@OpenAI</a>.</p><p>Justin Uberti described it as “Whisper, but now with realtime streaming” and updated demos to use the new model <a href="https://x.com/juberti/status/2052478775523512356" target="_blank" rel="noreferrer">@juberti</a>.</p><p>Uberti also built a delay selector to expose the latency/accuracy tradeoff in a real-time typing demo <a href="https://x.com/juberti/status/2052504986391879788" target="_blank" rel="noreferrer">@juberti</a>.</p><p>Product integrations and demos</p><p>Glean: shipped real-time voice powered by GPT-Realtime-2, grounded in organizational context; internal evals showed 42.9% relative helpfulness increase over the previous version <a href="https://x.com/glean/status/2052440702169108990" target="_blank" rel="noreferrer">@glean</a>.</p><p>Vimeo: demonstrated live dubbing using GPT-Realtime-Translate, with translations generated live and no pre-loaded captions <a href="https://x.com/Vimeo/status/2052442588201029684" target="_blank" rel="noreferrer">@Vimeo</a>.</p><p>Genspark: upgraded its Call for Me Agent to GPT-Realtime-2; Genspark Realtime Voice is next; claimed sharper reasoning, tighter instruction following, +26% effective conversation rate, and fewer dropped calls <a href="https://x.com/genspark_ai/status/2052524670088556557" target="_blank" rel="noreferrer">@genspark_ai</a>.</p><p>Gradient Bang / game-agent demo: Kyle Windland said GPT-Realtime-2 is the first OpenAI speech-to-speech model good enough for his voice agents that do “real work,” showing it as the ship AI in a complex agent with tool calls and subagents <a href="https://x.com/kwindla/status/2052521318688739811" target="_blank" rel="noreferrer">@kwindla</a>.</p><p>Voice-controlled market dashboard: Levin Stanley demoed GPT-Realtime-2 controlling an interface by intent—“Focus on Apple,” “How did it do over the last 30 days?”, “Go back”—arguing that real-time interruption and reasoning change the UI loop from navigation to direction <a href="https://x.com/levinstanley/status/2052506605044842672" target="_blank" rel="noreferrer">@levinstanley</a>.</p><p>Realtime demos: Justin Uberti updated hello-realtime for GPT-Realtime-2 and provided a phone demo number <a href="https://x.com/juberti/status/2052469176821002676" target="_blank" rel="noreferrer">@juberti</a>; Diego Cabezas posted a quick GPT-Realtime-2 demo <a href="https://x.com/diegocabezas01/status/2052492653082681485" target="_blank" rel="noreferrer">@diegocabezas01</a>; Ray Fernando hosted a “Building a Live Translator” broadcast <a href="https://x.com/RayFernando1337/status/2052479718495318143" target="_blank" rel="noreferrer">@RayFernando1337</a>.</p><p>Reachy Mini / robotics voice interface interest: Clement Delangue asked who would add the new voice capabilities to Reachy Mini <a href="https://x.com/ClementDelangue/status/2052449977725534363" target="_blank" rel="noreferrer">@ClementDelangue</a>, after earlier asking voice AI labs such as Gradium, Kyutai, and ElevenLabs who could help with a robot voice use case <a href="https://x.com/ClementDelangue/status/2052385809655828907" target="_blank" rel="noreferrer">@ClementDelangue</a>.</p><p>Why this matters</p><p>The launch pushes voice agents from “speech I/O wrapper around a chatbot” toward full-duplex, tool-using, long-context, reasoning agents. The technical shift is not just better ASR or TTS; it is the combination of low-latency turn-taking, interruption handling, longer context, tool-call transparency, and adjustable reasoning effort in a single real-time loop. That matters for customer support, meetings, accessibility, live translation, robotics, browser/computer control, and hands-free workflows where text chat is too slow or awkward.</p><p>The most important engineering implication is that voice apps now need to be designed as stateful real-time systems, not prompt-response endpoints. OpenAI’s prompting guide explicitly points developers toward reasoning-effort tuning, preambles, tool behavior, unclear-audio recovery, entity capture, and long-session state management <a href="https://x.com/OpenAIDevs/status/2052530378184032560" target="_blank" rel="noreferrer">@OpenAIDevs</a>. This suggests voice-agent quality will increasingly depend on harness design: latency budgets, interruption semantics, tool-call UX, conversational memory, and failure recovery—not just raw model selection.</p><p>The remaining uncertainty is distribution. The API model is available now, but ChatGPT voice mode has not yet received the upgrade, per Simon Willison’s observation <a href="https://x.com/simonw/status/2052439091577496054" target="_blank" rel="noreferrer">@simonw</a>. If and when ChatGPT Voice gets the same capabilities, the consumer impact could be much larger. Until then, the launch primarily benefits developers and platforms building specialized real-time agents.</p><p><a href="https://www.latent.space/p/ainews-gpt-realtime-2-translate-and" target="_blank" rel="noreferrer"> Read more </a></p><hr>',90)])])}const u=t(s,[["render",i]]);export{d as __pageData,u as default};
